prompt_en:
High-profile studio portrait with direct flash highlighting beauty, East Asian social media style (e.g., Ulzzang, Douyin), stylized beauty retouching.  
Output: {  
  color_profile: sRGB,  
  render_intent: photo  
}  

Subject: {  
  category: human,  
  gender_presentation: female,  
  ethnicity: East Asian (e.g., Korean, Chinese),  
  age_bracket: young adult,  
  body: {  
    build: slim,  
    proportions: natural human anatomy,  
    posture: relaxed sitting on a sofa, casually seated,  
    pose: sitting with legs crossed, body close to itself,  
    gesture: right hand raised with fingers loosely curled, back of hand or knuckles gently supporting chin and cheek,  
    head_tilt: 5°  
  },  
  face: {  
    expression: playful, alluring,  
    gaze: directly at the camera with right eye,  
    eye_action: winking with left eye,  
    skin_tone: very porcelain pale (bright aesthetic),  
    makeup: stylized Korean/Douyin makeup — matte flawless base, heavy pink blush on cheeks, pink gradient lips, defined eyebrows, subtle eyeliner, emphasizing a coquettish look,  
    features: small beauty mole below the left eye  
  },  
  hair: {  
    length: long,  
    style: messy high bun with loose strands and curtain bangs,  
    color: dark brown  
  },  
  wardrobe: {  
    top: white fitted cropped tank top,  
    outerwear: light gray zip-up hoodie worn open with slightly slipping shoulders,  
    bottom: white drawstring casual shorts,  
    footwear: barefoot  
  }  
}  

Environment: {  
  location: studio or minimalist interior,  
  set: black leather sofa against plain white or light gray wall,  
  props: silver laptop (Apple MacBook, visible logo) placed on cushion to the right of the subject (camera left)  
},  

Lighting: {  
  key: {  
    source: strobe/flash,  
    modifier: bare reflector or direct flash (hard light),  
    position: close to camera axis, slightly to the right and above eye level,  
    effect: clear, faint, well-defined shadows cast on the wall directly behind the subject; strong specular highlights on skin and sofa leather  
  },  
  fill: {  
    type: minimal or none  
  },  
  environment: subdued,  
  white_balance_kelvin: 5800K  
},  

Camera: {  
  system: digital camera,  
  sensor: full-frame equivalent,  
  lens: {  
    type: prime,  
    focal_length_mm: 50  
  },  
  settings: {  
    ISO: 100,  
    aperture_f: 4.0,  
    metering: bright exposure with high-key aesthetic  
  },  
  focus_target: near eye (right eye),  
  depth_of_field: medium,  
  framing: {  
    orientation: vertical,  
    crop: from mid-thigh to top of head with space above hair,  
    angle: eye-level,  
    composition: centered subject  
  }  
},  

Color grading: {  
  look: bright, clean, slightly cool tones,  
  contrast: high,  
  saturation: medium with emphasis on pinks  
},  

Post-processing: {  
  noise_reduction: high,  
  texture: skin highly smooth, poreless (porcelain doll or beauty filter effect),  
  sharpening: selectively on eyes and eyelashes,  
  blemish_control: completely remove all blemishes and textures  
},  

Quality goals: [  
  accurate limb length and joint angles,  
  correct finger count and positioning,  
  realistic fabric tension and folds,  
  precise blinking expressions  
],  

Negative prompts: [  
  no body proportion distortions or exaggerations,  
  no extra or fused fingers,  
  no real skin textures, pores, or blemishes,  
  no text or watermarks (except specified logos),  
  no extreme wide-angle distortion,  
  no NSFW content,  
  no dark or moody lighting,  
  no warm tones  
]

prompt:
